sys_ui_page.client_script:
//Client Script of UI Page

// Create an event listener on change
upFile.addEventListener('change', attachFiles, false);

// Enhanced UI interaction functions
function updateUploadUI(file) {
	var uploadLabel = document.getElementById('uploadLabel');

	if (file) {
		// Update UI to show file is selected
		uploadLabel.classList.add('success');
		uploadLabel.querySelector('.upload-icon').textContent = '✅';
		uploadLabel.querySelector('.upload-text').textContent = 'File Selected';
		uploadLabel.querySelector('.upload-subtext').textContent = file.name;
	} else {
		// Reset UI if no file selected
		resetUploadUI();
	}
}

function resetUploadUI() {
	var uploadLabel = document.getElementById('uploadLabel');
	uploadLabel.classList.remove('success', 'loading');
	uploadLabel.querySelector('.upload-icon').textContent = '📁';
	uploadLabel.querySelector('.upload-text').textContent = 'Click to upload file';
	uploadLabel.querySelector('.upload-subtext').textContent = 'or drag and drop';
}

function showLoadingUI() {
	var uploadLabel = document.getElementById('uploadLabel');
	uploadLabel.classList.add('loading');
	uploadLabel.querySelector('.upload-icon').textContent = '⏳';
	uploadLabel.querySelector('.upload-text').textContent = 'Uploading...';
	uploadLabel.querySelector('.upload-subtext').textContent = 'Please wait';
}

function attachFiles(evt) {
	var filename = evt.target.files[0].name;
	var file = evt.target.files[0];
	var userToken = document.getElementById('sysparm_ck').value;
	// Update UI immediately when file is selected
	updateUploadUI(file);

	var recSysID = document.getElementById("sysparm_rec_sys_id").value;
	var tableName = document.getElementById("sysparm_table_name").value;



	// Get the content type of the first File object
	var contentType = evt.target.files[0].type;

	// Passing the values to the html view with enhanced display
	fname.innerText = filename;
	type.innerText = contentType || 'Unknown';

	// Show file size and additional info
	var fileSize = (file.size / 1024).toFixed(2) + ' KB';
	var lastModified = new Date(file.lastModified).toLocaleDateString();
	fdata.innerHTML = '<strong>Size:</strong> ' + fileSize + '<br><strong>Modified:</strong> ' + lastModified;

	// Show loading state
	showLoadingUI();

	// Attachment REST API
	var url = "/api/now/attachment/file?file_name=" + encodeURIComponent(filename) +
		"&table_name=" + tableName +
		"&table_sys_id=" + recSysID;

	var oReq = new XMLHttpRequest();
	// oReq.withCredentials = true;
	oReq.open("POST", url, true);

	// Set correct content type 
	oReq.setRequestHeader("Content-Type", file.type);

	oReq.setRequestHeader("X-UserToken", userToken);

	oReq.onload = function (oEvent) {
		if (oReq.status >= 200 && oReq.status < 300) {
			var response = JSON.parse(oReq.responseText);
			var result = response.result;

			// Update UI to show success
			var uploadLabel = document.getElementById('uploadLabel');
			uploadLabel.classList.remove('loading');
			uploadLabel.classList.add('success');
			uploadLabel.querySelector('.upload-icon').textContent = '✅';
			uploadLabel.querySelector('.upload-text').textContent = 'Upload Successful';
			uploadLabel.querySelector('.upload-subtext').textContent = 'File processed successfully';

			// Now we have the sys_id of the attachment, we need to validate the uploaded file
			var successMessage = document.createElement('div');
			successMessage.style.marginTop = '10px';
			successMessage.style.padding = '10px';
			successMessage.style.backgroundColor = '#d4edda';
			successMessage.style.border = '1px solid #c3e6cb';
			successMessage.style.borderRadius = '8px';
			successMessage.style.color = '#155724';

			var span = document.createElement('span');
			span.innerText = "File uploaded successfully to ";

			var anchor = document.createElement('a');
			anchor.href = '/' + tableName + '.do?sys_id=' + result.table_sys_id;
			anchor.innerText = 'Current Record';
			anchor.style.color = '#155724';
			anchor.style.fontWeight = 'bold';
			anchor.style.textDecoration = 'underline';

			span.appendChild(anchor);
			successMessage.appendChild(span);

			// Clear previous content and add success message
			fdata.innerHTML = '';
			fdata.appendChild(successMessage);

			// Call validation function
			validateExcel(result.sys_id, result.file_name, recSysID);
		} else {
			// Handle error state
			var uploadLabel = document.getElementById('uploadLabel');
			uploadLabel.classList.remove('loading');
			uploadLabel.querySelector('.upload-icon').textContent = '❌';
			uploadLabel.querySelector('.upload-text').textContent = 'Upload Failed';
			uploadLabel.querySelector('.upload-subtext').textContent = 'Please try again';
			alert(JSON.stringify(oReq))
			alert("Upload failed: " + oReq.statusText);
		}
	};

	oReq.onerror = function () {
		// Handle network error
		var uploadLabel = document.getElementById('uploadLabel');
		uploadLabel.classList.remove('loading');
		uploadLabel.querySelector('.upload-icon').textContent = '❌';
		uploadLabel.querySelector('.upload-text').textContent = 'Network Error';
		uploadLabel.querySelector('.upload-subtext').textContent = 'Check your connection';
		alert(JSON.stringify(oReq))
		alert("Network error occurred during upload");
	};

	// Send the actual file
	oReq.send(file);
}

function validateExcel(file, fileName, recSysID) {
	// Show validation is starting
	showValidationUI();

	var att = new GlideAjax('x_adga_project_p_0.ProjectPermissionManagementfromClient');
	att.addParam('sysparm_name', "handleMonthlyExcel");
	att.addParam('sysparam_attachment_id', file);
	att.addParam('sysparam_file_name', fileName);
	att.addParam('sysparam_scope_sys_id', recSysID);
	att.getXML(callBackFun);
}

function showValidationUI() {
	var uploadLabel = document.getElementById('uploadLabel');
	uploadLabel.querySelector('.upload-icon').textContent = '⚡';
	uploadLabel.querySelector('.upload-text').textContent = 'Validating Excel...';
	uploadLabel.querySelector('.upload-subtext').textContent = 'Processing data';

	// Add validation message to fdata
	var validatingDiv = document.createElement('div');
	validatingDiv.id = 'validating-message';
	validatingDiv.style.marginTop = '10px';
	validatingDiv.style.padding = '15px';
	validatingDiv.style.backgroundColor = '#fff3cd';
	validatingDiv.style.border = '1px solid #ffeaa7';
	validatingDiv.style.borderRadius = '8px';
	validatingDiv.style.color = '#856404';
	validatingDiv.innerHTML = '<strong>⏳ Validating Excel file...</strong><br>Processing rows and updating activities';

	fdata.appendChild(validatingDiv);
}

function callBackFun(response) {
	// Remove validating message
	var validatingMsg = document.getElementById('validating-message');
	if (validatingMsg) {
		validatingMsg.remove();
	}

	var answer = response.responseXML.documentElement.getAttribute("answer");
	var uploadLabel = document.getElementById('uploadLabel');

	if (answer) {
		try {
			var result = JSON.parse(answer);

			if (result.success) {
				handleSuccessResponse(result);
			} else {
				handleErrorResponse(result);
			}

		} catch (parseError) {
			// Handle old format or invalid JSON
			alert("Validation response (legacy): " + answer);
			handleLegacyResponse(answer);
		}
	} else {
		// No response received
		uploadLabel.querySelector('.upload-icon').textContent = '❌';
		uploadLabel.querySelector('.upload-text').textContent = 'Validation Failed';
		uploadLabel.querySelector('.upload-subtext').textContent = 'No response received';

		showErrorMessage("No validation response received", "Please check the server logs for details.");
	}
}

function handleSuccessResponse(result) {
	var uploadLabel = document.getElementById('uploadLabel');

	// Update upload label to show completion
	uploadLabel.querySelector('.upload-icon').textContent = '✅';
	uploadLabel.querySelector('.upload-text').textContent = 'Processing Complete';
	uploadLabel.querySelector('.upload-subtext').textContent = 'Excel validated and processed';

	// Create detailed success message
	var successDiv = document.createElement('div');
	successDiv.style.marginTop = '10px';
	successDiv.style.padding = '15px';
	successDiv.style.backgroundColor = '#d4edda';
	successDiv.style.border = '1px solid #c3e6cb';
	successDiv.style.borderRadius = '8px';
	successDiv.style.color = '#155724';

	var stats = result.stats;
	var summary = '<strong>✅ Excel Processing Complete</strong><br>';
	summary += '<strong>File:</strong> ' + result.fileName + '<br><br>';

summary += '<strong>Processing Summary:</strong><br>';
summary += '• Total Rows: ' + stats.totalRows + '<br>';
summary += '• Successfully Processed: ' + stats.processed + '<br>';
summary += '• Records Updated: ' + stats.updated + '<br>';
summary += '• Records Skipped: ' + stats.skipped + '<br>';

// Highlight "Errors" row in red if any
if (stats.errors > 0) {
	summary += '<div style="background-color:#f8d7da; color:#721c24; padding:4px; border-radius:4px; display:inline-block;">';
	summary += '• Errors: ' + stats.errors + '<br>';
	summary += '</div>';
} else {
	summary += '• Errors: ' + stats.errors + '<br>';
}

// Validation Issues section with red background
if (result.validationErrors && result.validationErrors.length > 0) {
	summary += '<br><strong>⚠️ Validation Issues:</strong><br>';
	result.validationErrors.forEach(function (error) {
		summary += '<div style="background-color:#f8d7da; color:#721c24; padding:4px; border-radius:4px; margin:2px 0;">';
		summary += '• ' + error + '<br>';
		summary += '</div>';
	});
}

successDiv.innerHTML = summary;
fdata.appendChild(successDiv);

// Show completion message
if (stats.errors > 0) {
	alert('Processing completed with ' + stats.errors + ' errors. Check the details below.');
} else {
	alert('Excel file processed successfully! ' + stats.updated + ' records updated.');
}

}

function handleErrorResponse(result) {
	var uploadLabel = document.getElementById('uploadLabel');

	// Update upload label to show error
	uploadLabel.querySelector('.upload-icon').textContent = '❌';
	uploadLabel.querySelector('.upload-text').textContent = 'Validation Failed';
	uploadLabel.querySelector('.upload-subtext').textContent = 'Check error details below';

	showErrorMessage(result.message, result.details, result);

	// Show error alert
	alert('Validation failed: ' + result.message);
}

function handleLegacyResponse(answer) {
	var uploadLabel = document.getElementById('uploadLabel');

	uploadLabel.querySelector('.upload-icon').textContent = '✅';
	uploadLabel.querySelector('.upload-text').textContent = 'Processing Complete';
	uploadLabel.querySelector('.upload-subtext').textContent = 'Legacy response format';

	// Legacy format handling
	var validationResult = document.createElement('div');
	validationResult.style.marginTop = '10px';
	validationResult.style.padding = '15px';
	validationResult.style.backgroundColor = '#cce5ff';
	validationResult.style.border = '1px solid #80bfff';
	validationResult.style.borderRadius = '8px';
	validationResult.style.color = '#004085';
	validationResult.innerHTML = '<strong>Validation Result:</strong><br>' + answer;

	fdata.appendChild(validationResult);
}

function showErrorMessage(message, details, result) {
	var errorDiv = document.createElement('div');
	errorDiv.style.marginTop = '10px';
	errorDiv.style.padding = '15px';
	errorDiv.style.backgroundColor = '#f8d7da';
	errorDiv.style.border = '1px solid #f5c6cb';
	errorDiv.style.borderRadius = '8px';
	errorDiv.style.color = '#721c24';

	var errorHtml = '<strong>❌ Validation Error</strong><br>';
	errorHtml += '<strong>Message:</strong> ' + message + '<br>';

	if (details) {
		errorHtml += '<strong>Details:</strong> ' + details + '<br>';
	}

	if (result && result.expectedHeaders && result.foundHeaders) {
		errorHtml += '<br><strong>Expected Headers:</strong><br>';
		result.expectedHeaders.forEach(function (header) {
			errorHtml += '• ' + header + '<br>';
		});

		errorHtml += '<br><strong>Found Headers:</strong><br>';
		result.foundHeaders.forEach(function (header) {
			errorHtml += '• ' + header + '<br>';
		});
	}

	errorDiv.innerHTML = errorHtml;
	fdata.appendChild(errorDiv);
}

// Enhanced drag and drop functionality
function initializeDragAndDrop() {
	var uploadLabel = document.getElementById('uploadLabel');

	if (uploadLabel) {
		['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventName => {
			uploadLabel.addEventListener(eventName, preventDefaults, false);
			document.body.addEventListener(eventName, preventDefaults, false);
		});

		['dragenter', 'dragover'].forEach(eventName => {
			uploadLabel.addEventListener(eventName, highlight, false);
		});

		['dragleave', 'drop'].forEach(eventName => {
			uploadLabel.addEventListener(eventName, unhighlight, false);
		});

		uploadLabel.addEventListener('drop', handleDrop, false);
	}
}

function preventDefaults(e) {
	e.preventDefault();
	e.stopPropagation();
}

function highlight(e) {
	var uploadLabel = document.getElementById('uploadLabel');
	uploadLabel.style.borderColor = '#764ba2';
	uploadLabel.style.background = 'linear-gradient(45deg, rgba(102, 126, 234, 0.15), rgba(118, 75, 162, 0.15))';
}

function unhighlight(e) {
	var uploadLabel = document.getElementById('uploadLabel');
	uploadLabel.style.borderColor = '#667eea';
	uploadLabel.style.background = 'linear-gradient(45deg, rgba(102, 126, 234, 0.05), rgba(118, 75, 162, 0.05))';
}

function handleDrop(e) {
	var dt = e.dataTransfer;
	var files = dt.files;

	if (files.length > 0) {
		document.getElementById('upFile').files = files;
		// Manually trigger the change event
		var event = new Event('change', { bubbles: true });
		document.getElementById('upFile').dispatchEvent(event);
	}
}

// Initialize drag and drop when the page loads
window.addEventListener('load', function () {
	initializeDragAndDrop();
});

