	validationResult.style.color = '#004085';
	validationResult.innerHTML = '<strong>Validation Result:</strong><br>' + answer;

	fdata.appendChild(validationResult);
}

function showErrorMessage(message, details, result) {
	var errorDiv = document.createElement('div');
	errorDiv.style.marginTop = '10px';
	errorDiv.style.padding = '15px';
	errorDiv.style.backgroundColor = '#f8d7da';
	errorDiv.style.border = '1px solid #f5c6cb';
	errorDiv.style.borderRadius = '8px';
	errorDiv.style.color = '#721c24';

	var errorHtml = '<strong>❌ Validation Error</strong><br>';
	errorHtml += '<strong>Message:</strong> ' + message + '<br>';

	if (details) {
		errorHtml += '<strong>Details:</strong> ' + details + '<br>';
	}

	if (result && result.expectedHeaders && result.foundHeaders) {
		errorHtml += '<br><strong>Expected Headers:</strong><br>';
		result.expectedHeaders.forEach(function (header) {
			errorHtml += '• ' + header + '<br>';
		});

		errorHtml += '<br><strong>Found Headers:</strong><br>';
		result.foundHeaders.forEach(function (header) {
			errorHtml += '• ' + header + '<br>';
		});
	}

	errorDiv.innerHTML = errorHtml;
	fdata.appendChild(errorDiv);
}

// Enhanced drag and drop functionality
function initializeDragAndDrop() {
	var uploadLabel = document.getElementById('uploadLabel');

	if (uploadLabel) {
		['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventName => {
			uploadLabel.addEventListener(eventName, preventDefaults, false);
			document.body.addEventListener(eventName, preventDefaults, false);
		});

		['dragenter', 'dragover'].forEach(eventName => {
			uploadLabel.addEventListener(eventName, highlight, false);
		});

		['dragleave', 'drop'].forEach(eventName => {
			uploadLabel.addEventListener(eventName, unhighlight, false);
		});

		uploadLabel.addEventListener('drop', handleDrop, false);
	}
}

function preventDefaults(e) {
	e.preventDefault();
	e.stopPropagation();
}

function highlight(e) {
	var uploadLabel = document.getElementById('uploadLabel');
	uploadLabel.style.borderColor = '#764ba2';
	uploadLabel.style.background = 'linear-gradient(45deg, rgba(102, 126, 234, 0.15), rgba(118, 75, 162, 0.15))';
}

function unhighlight(e) {
	var uploadLabel = document.getElementById('uploadLabel');
	uploadLabel.style.borderColor = '#667eea';
	uploadLabel.style.background = 'linear-gradient(45deg, rgba(102, 126, 234, 0.05), rgba(118, 75, 162, 0.05))';
}

function handleDrop(e) {
	var dt = e.dataTransfer;
	var files = dt.files;

	if (files.length > 0) {
		document.getElementById('upFile').files = files;
		// Manually trigger the change event
		var event = new Event('change', { bubbles: true });
		document.getElementById('upFile').dispatchEvent(event);
	}
}

// Initialize drag and drop when the page loads
window.addEventListener('load', function () {
	initializeDragAndDrop();
});
